85→    private fun writeDrawerConfig(editor: StorageEditor, config: DrawerConfig) {
86→        editor.putBoolean("showAccountSelector", config.showAccountSelector)
87→        editor.putBoolean("showUnifiedInbox", config.showUnifiedFolders)
88→        editor.putBoolean("showStarredCount", config.showStarredCount)
89→    }
